 1	import * as React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import { ClipboardCopyButton } from '@patternfly/react-core';
 4	
 5	import { useBoolean } from '../hooks/useBoolean';
 6	
 7	type Props = {
 8	  className?: string;
 9	  value: string;
10	};
11	
12	const CopyAction: React.FC<Props> = ({ className, value }) => {
13	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
14	
15	  const [isCopied, , setCopied, setNotCopied] = useBoolean(false);
16	
17	  return (
18	    <ClipboardCopyButton
19	      aria-label={t('Copy to clipboard')}
20	      className={className}
21	      exitDelay={isCopied ? 1500 : 600}
22	      id="ols-plugin-copy-button"
23	      onClick={() => {
24	        try {
25	          navigator.clipboard.writeText(value);
26	          setCopied();
27	        } catch (err) {
28	          // eslint-disable-next-line no-console
29	          console.error('Failed to copy to clipboard: ', err);
30	        }
31	      }}
32	      onTooltipHidden={setNotCopied}
33	      textId="code-content"
34	      variant="plain"
35	    >
36	      {isCopied ? t('Copied') : t('Copy to clipboard')}
37	    </ClipboardCopyButton>
38	  );
39	};
40	
41	export default CopyAction;

